class ProposalDatabase:
    def __init__(self, path: Path):
        self.path = path
        self.base_dir = path.resolve().parent
        self.conn = sqlite3.connect(path)
        self.conn.row_factory = sqlite3.Row
        self._ensure_schema()

    def _ensure_schema(self):
        self.conn.execute(
            """
            CREATE TABLE IF NOT EXISTS proposals (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                ficha_name TEXT NOT NULL,
                company_name TEXT NOT NULL,
                cnpj TEXT NOT NULL,
                status TEXT NOT NULL,
                monthly_full REAL NOT NULL,
                monthly_contract REAL NOT NULL,
                annual_full REAL NOT NULL,
                annual_contract REAL NOT NULL,
                extras_total REAL NOT NULL,
                payload_json TEXT NOT NULL,
                updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                UNIQUE(ficha_name, company_name, cnpj)
            )
            """
        )
        self.conn.commit()

    def save_proposal(self, ficha_name: str, payload: dict, totals: dict, extras_total: float, status: str):
        company_name = payload.get("company_name", "").strip()
        cnpj = payload.get("cnpj", "").strip()
        if not company_name:
            raise ValueError("Informe a Razão Social antes de salvar.")

        self.conn.execute(
            """
            INSERT INTO proposals (
                ficha_name, company_name, cnpj, status,
                monthly_full, monthly_contract, annual_full, annual_contract,
                extras_total, payload_json, updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
            ON CONFLICT(ficha_name, company_name, cnpj) DO UPDATE SET
                status=excluded.status,
                monthly_full=excluded.monthly_full,
                monthly_contract=excluded.monthly_contract,
                annual_full=excluded.annual_full,
                annual_contract=excluded.annual_contract,
                extras_total=excluded.extras_total,
                payload_json=excluded.payload_json,
                updated_at=CURRENT_TIMESTAMP
            """,
            (
                ficha_name,
                company_name,
                cnpj,
                status,
                totals.get("monthly_full", 0.0),
                totals.get("monthly_contract", 0.0),
                totals.get("annual_full", 0.0),
                totals.get("annual_contract", 0.0),
                extras_total,
                json.dumps(payload, ensure_ascii=False),
            ),
        )
        self.conn.commit()

    def search(self, company_name: str) -> list[sqlite3.Row]:
        term = company_name.strip()
        if not term:
            return list(
                self.conn.execute(
                    """
                    SELECT ficha_name, company_name, cnpj, status, monthly_contract,
                           extras_total, payload_json, updated_at
                    FROM proposals
                    ORDER BY updated_at DESC, id DESC
                    LIMIT 100
                    """
                )
            )
        return list(
            self.conn.execute(
                """
                SELECT ficha_name, company_name, cnpj, status, monthly_contract,
                       extras_total, payload_json, updated_at
                FROM proposals
                WHERE company_name LIKE ?
                ORDER BY updated_at DESC, id DESC
                """,
                (f"%{term}%",),
            )
        )

    def get_proposal(self, ficha_name: str, company_name: str, cnpj: str) -> sqlite3.Row | None:
        return self.conn.execute(
            "SELECT * FROM proposals WHERE ficha_name = ? AND company_name = ? AND cnpj = ?",
            (ficha_name, company_name, cnpj),
        ).fetchone()

    def delete_proposal(self, ficha_name: str, company_name: str, cnpj: str):
        self.conn.execute(
            "DELETE FROM proposals WHERE ficha_name = ? AND company_name = ? AND cnpj = ?",
            (ficha_name, company_name, cnpj),
        )
        self.conn.commit()

    def update_analysis_reason(self, ficha_name: str, company_name: str, cnpj: str, reason: str):
        row = self.get_proposal(ficha_name, company_name, cnpj)
        if row is None:
            return
        payload = json.loads(row["payload_json"])
        payload["analysis_reason"] = reason
        self.conn.execute(
            """
            UPDATE proposals
            SET payload_json = ?, updated_at = CURRENT_TIMESTAMP
            WHERE ficha_name = ? AND company_name = ? AND cnpj = ?
            """,
            (json.dumps(payload, ensure_ascii=False), ficha_name, company_name, cnpj),
        )
        self.conn.commit()

    def update_status(self, ficha_name: str, company_name: str, cnpj: str, status: str):
        row = self.get_proposal(ficha_name, company_name, cnpj)
        if row is None:
            return
        payload = json.loads(row["payload_json"])
        payload["_status"] = status
        self.conn.execute(
            """
            UPDATE proposals
            SET status = ?, payload_json = ?, updated_at = CURRENT_TIMESTAMP
            WHERE ficha_name = ? AND company_name = ? AND cnpj = ?
            """,
            (status, json.dumps(payload, ensure_ascii=False), ficha_name, company_name, cnpj),
        )
        self.conn.commit()

    def update_payload_fields(self, ficha_name: str, company_name: str, cnpj: str, fields: dict):
        row = self.get_proposal(ficha_name, company_name, cnpj)
        if row is None:
            return
        payload = json.loads(row["payload_json"])
        payload.update(fields)
        self.conn.execute(
            """
            UPDATE proposals
            SET payload_json = ?, updated_at = CURRENT_TIMESTAMP
            WHERE ficha_name = ? AND company_name = ? AND cnpj = ?
            """,
            (json.dumps(payload, ensure_ascii=False), ficha_name, company_name, cnpj),
        )
        self.conn.commit()

    def next_revision_number(self, base_ficha_name: str, company_name: str, cnpj: str) -> int:
        rows = self.conn.execute(
            """
            SELECT ficha_name
            FROM proposals
            WHERE company_name = ? AND cnpj = ? AND (ficha_name = ? OR ficha_name LIKE ?)
            """,
            (company_name, cnpj, base_ficha_name, f"{base_ficha_name} RV%"),
        ).fetchall()
        max_revision = 0
        for row in rows:
            match = re.search(r"\sRV(\d+)$", row["ficha_name"])
            if match:
                max_revision = max(max_revision, int(match.group(1)))
        return max_revision + 1

    def status_counts(self) -> dict[str, int]:
        counts = {"Proposta Aceita": 0, "Proposta Recusada": 0, "Proposta em Analise": 0}
        for row in self.conn.execute("SELECT status, COUNT(*) total FROM proposals GROUP BY status"):
            if row["status"] in counts:
                counts[row["status"]] = row["total"]
        return counts


class WorkbookModel:
    def __init__(self, path: Path | None = None):
        self.wb = None
        self.ws_base = None
        self.ws_params = None
        self.params: dict[str, str] = {}
        self.base_rows: list[dict] = []
        self.param_rows: list[list] = []
        self.cache_file = PROJECT_ROOT / CACHE_FILE_NAME

        if path and path.exists():
            self.wb = load_workbook(path, data_only=True)
            self.ws_base = self.wb["Base"]
            self.ws_params = self.wb[self._sheet_name("Par")]
            self.params = self._load_params()
            self.base_rows = self._load_base()
            self.param_rows = self._load_param_rows()
            self._save_cache()
        else:
            self._load_cache()

    def _sheet_name(self, starts_with: str) -> str:
        for name in self.wb.sheetnames:
            if name.startswith(starts_with):
                return name
        raise KeyError(starts_with)

    def _load_params(self) -> dict[str, str]:
        params = {}
        for row in self.ws_params.iter_rows(min_row=1, values_only=True):
            if row[0] and row[1]:
                params[str(row[0])] = str(row[1])
        return params

    def _load_param_rows(self) -> list[list]:
        return [list(row) for row in self.ws_params.iter_rows(min_row=1, max_row=11, values_only=True)]

    def _load_base(self) -> list[dict]:
        rows = []
        for row in self.ws_base.iter_rows(min_row=2, values_only=True):
            if not row[0] or not row[2] or not row[3]:
                continue
            rows.append(
                {
                    "code": str(row[0]),
                    "description": str(row[1]),
                    "segment": str(row[2]),
                    "table": str(row[3]),
                    "values": [to_float(value) for value in row[4:15]],
                    "display_values": ["" if value is None else str(value) for value in row[4:15]],
                }
            )
        return rows

    def _save_cache(self):
        payload = {
            "params": self.params,
            "base_rows": self.base_rows,
            "param_rows": self.param_rows,
        }
        self.cache_file.write_text(json.dumps(payload, ensure_ascii=False), encoding="utf-8")

    def _load_cache(self):
        if self.cache_file.exists():
            payload = json.loads(self.cache_file.read_text(encoding="utf-8"))
        elif EMBEDDED_PRICING_DATA:
            raw = gzip.decompress(base64.b64decode(EMBEDDED_PRICING_DATA.encode("ascii")))
            payload = json.loads(raw.decode("utf-8"))
            try:
                self.cache_file.write_text(json.dumps(payload, ensure_ascii=False), encoding="utf-8")
            except Exception:
                pass
        else:
            raise FileNotFoundError("Não encontrei a planilha de preços nem a base interna do sistema.")
        self.params = payload.get("params", {})
        self.base_rows = payload.get("base_rows", [])
        self.param_rows = payload.get("param_rows", [])

    @property
    def segments(self) -> list[str]:
        ordered = ["Comércio", "Serviço", "Indústria", "Construção"]
        available = {row["segment"] for row in self.base_rows}
        return [item for item in ordered if item in available]

    @property
    def tables(self) -> list[str]:
        return ["A", "B", "R"]

    @property
    def taxes(self) -> list[str]:
        return list(self.params.keys())

    def unit_values(self, code: str, segment: str, table: str) -> list[float]:
        for item in self.base_rows:
            if item["code"] == code and item["segment"] == segment and item["table"] == table:
                return [value for value in item["values"] if value > 0]
        return []

    def base_row_values(self, code: str, segment: str, table: str) -> list[float]:
        for item in self.base_rows:
            if item["code"] == code and item["segment"] == segment and item["table"] == table:
                return item["values"]
        return []

    def base_unit(self, code: str, segment: str, table: str, level: int) -> float:
        values = self.unit_values(code, segment, table)
        if not values:
            return 0.0
        index = max(1, min(level, len(values))) - 1
        return values[index]

    def fiscal_level(self, qty: float) -> int:
        for row in self.param_rows:
            level, start, end = row[3], row[6], row[7]
            if level and to_float(start) <= qty <= to_float(end):
                return int(level)
        return 1

    def people_level(self, qty: float) -> int:
        for row in self.param_rows:
            level, start, end = row[3], row[4], row[5]
            if level and to_float(start) <= qty <= to_float(end):
                return int(level)
        return 1

    def calculate(self, values: dict, unit_overrides: dict[str, float] | None = None) -> tuple[list[PriceRow], dict]:
        segment = values["segment"]
        table = values["table"]
        tax = values["tax"]
        rows: list[PriceRow] = []
        unit_overrides = unit_overrides or {}

        def add(seq, desc, indicator, qty, unit, discount=0.0, contract_rule="20pct"):
            unit = unit_overrides.get(str(seq), unit)
            subtotal = qty * unit
            total = subtotal - discount
            contract = total * (1 - DISCOUNT_RATE) if contract_rule == "20pct" else total
            rows.append(PriceRow(str(seq), desc, indicator, qty, unit, subtotal, discount, total, 0.0, contract, 0.0))

        tax_code = self.params.get(tax, "")
        unit_tax = self.base_unit(tax_code, segment, table, 1)
        add("1.2", "Tributação Federal", tax, to_float(values["tax_qty"]), unit_tax)

        branch_qty = to_float(values["branch_qty"])
        add("1.4", "Empresa com Filiais", values["branches"], branch_qty, unit_tax * 0.10 if values["branches"] == "Sim" else 0.0)

        account_qty = to_float(values["accounting_qty"])
        account_level = self.fiscal_level(account_qty)
        account_unit = self.base_unit("2.1", segment, table, account_level)
        account_subtotal = account_qty * account_unit
        add(
            "2.1",
            "Lançamento Contábil",
            values["accounting_mode"],
            account_qty,
            account_unit,
            account_subtotal * IMPORT_DISCOUNT_RATE if values["accounting_mode"] == "Registros Importados" else 0.0,
        )

        employee_qty = to_float(values["employees_qty"])
        partner_qty = to_float(values["partners_qty"])
        people_total = employee_qty + partner_qty
        people_level = self.people_level(people_total)
        for seq, desc, qty, mode, code in [
            ("3.1", "Número de Funcionários", employee_qty, values["employees_mode"], "3.1"),
            ("3.2", "Número de Sócios", partner_qty, values["partners_mode"], "3.2"),
        ]:
            unit = self.base_unit(code, segment, table, people_level) if people_total > 0 else 0.0
            subtotal = qty * unit
            add(seq, desc, mode, qty, unit, subtotal * IMPORT_DISCOUNT_RATE if mode == "Registros Importados" else 0.0, "minus_share")

        fiscal_items = [
            ("4.1", "Notas Fiscais de Entrada", "nf_in_qty", "nf_in_mode"),
            ("4.2", "Notas Fiscais de Saída", "nf_out_qty", "nf_out_mode"),
            ("4.3", "Notas Fiscais de Serviços Prestados", "service_out_qty", "service_out_mode"),
            ("4.4", "Notas Fiscais de Serviços Tomados", "service_in_qty", "service_in_mode"),
            ("4.5", "Notas de Locação", "rental_qty", "rental_mode"),
            ("4.6", "Notas Fiscais p/Apuração do IPI", "ipi_qty", "ipi_mode"),
        ]
        fiscal_total_qty = sum(to_float(values[qty_key]) for _, _, qty_key, _ in fiscal_items)
        fiscal_level = self.fiscal_level(fiscal_total_qty)
        for seq, desc, qty_key, mode_key in fiscal_items:
            qty = to_float(values[qty_key])
            mode = values[mode_key]
            unit = self.base_unit(seq, segment, table, fiscal_level) if fiscal_total_qty > 0 else 0.0
            subtotal = qty * unit
            add(seq, desc, mode, qty, unit, subtotal * IMPORT_DISCOUNT_RATE if mode == "Registros Importados" else 0.0, "minus_share")

        audit_qty = to_float(values["audit_hours"])
        audit_level = self.people_level(audit_qty)
        audit_unit = self.base_unit("5.1", segment, table, audit_level) if audit_qty > 0 else 0.0
        add("5.1", "Auditoria Externa (Horas)", values["audit"], audit_qty, audit_unit, 0.0, "minus_share")

        total_full = sum(row.total for row in rows)
        adjusted_rows = []
        contract_total = 0.0
        for row in rows:
            share = row.total / total_full if total_full else 0.0
            contract = row.contract
            if row.seq.startswith(("3.", "4.", "5.")):
                contract = row.total - share
            contract_share = contract / total_full if total_full else 0.0
            contract_total += contract
            adjusted_rows.append(
                PriceRow(
                    row.seq,
                    row.description,
                    row.indicator,
                    row.qty,
                    row.unit,
                    row.subtotal,
                    row.discount,
                    row.total,
                    share,
                    contract,
                    contract_share,
                )
            )

        return adjusted_rows, {
            "monthly_full": total_full,
            "monthly_contract": contract_total,
            "annual_full": total_full * 13,
            "annual_contract": contract_total * 13,
        }


class PriceApp:
    def __init__(self, root: Tk, model: WorkbookModel, database: ProposalDatabase):
        self.root = root
        self.model = model
        self.database = database
        self.root.title("Ficha de Formação de Preços 2026")
        self.root.geometry("1280x900")
        self.root.configure(bg=APP_BG)

        self.logo_image = None
        self.current_ficha = StringVar(value=FICHA_NAMES[0])
        self.group_var = IntVar(value=0)
        self.search_company = StringVar(value="")
        self.form_vars: dict[str, StringVar] = {}
        self.form_widgets: dict[str, object] = {}
        self.is_loading_ficha = False
        self.view_only_mode = False
        self.view_mode_restore_state: dict | None = None
        self.selected_proposal_key: tuple[str, str, str] | None = None
        self.selected_services = {name: [] for name in FICHA_NAMES}
        self.ficha_store = {
            name: {
                "values": dict(DEFAULT_FICHA_TEMPLATE),
                "rows": [],
                "totals": {"monthly_full": 0.0, "monthly_contract": 0.0, "annual_full": 0.0, "annual_contract": 0.0},
                "status": "",
                "record_ficha_name": name,
                "unit_overrides": {},
            }
            for name in FICHA_NAMES
        }
        self.unit_editor: ttk.Combobox | None = None
        self.unit_editor_item: str | None = None

        self._configure_style()
        self._build()
        self._load_ficha(FICHA_NAMES[0])
        self.recalculate()

    def _configure_style(self):
        style = ttk.Style()
        style.theme_use("clam")
        style.configure("TNotebook", background=APP_BG, borderwidth=0)
        style.configure("TNotebook.Tab", background=TAB_BG, foreground="#003B5C", padding=(16, 8), font=("Segoe UI", 10, "bold"))
        style.map("TNotebook.Tab", background=[("selected", TAB_SELECTED)], foreground=[("selected", "white")])
        style.configure("Treeview.Heading", background=TAB_SELECTED, foreground="white", font=("Segoe UI", 12, "bold"))
        style.configure("Treeview", background="white", fieldbackground="white", foreground="#1F1F1F", rowheight=24)
        style.configure("ImplantationPending.TCombobox", fieldbackground="white", background="white", foreground="#1F1F1F")
        style.map(
            "ImplantationPending.TCombobox",
            fieldbackground=[("readonly", "white")],
            background=[("readonly", "white")],
            foreground=[("readonly", "#1F1F1F")],
        )
        style.configure("ImplantationDone.TCombobox", fieldbackground="#E6F7E8", background="#E6F7E8", foreground="#1F1F1F")
        style.map(
            "ImplantationDone.TCombobox",
            fieldbackground=[("readonly", "#E6F7E8")],
            background=[("readonly", "#E6F7E8")],
            foreground=[("readonly", "#1F1F1F")],
        )

    def _build(self):
        header = Frame(self.root, padx=16, pady=6, bg=HEADER_BG)
        header.pack(fill=X)

        title_area = Frame(header, bg=HEADER_BG)
        title_area.pack(side=LEFT, fill=X, expand=True)
        Label(title_area, text="Ficha de Formação de Preços 2026", font=("Segoe UI", 16, "bold"), bg=HEADER_BG, fg="#003B5C").pack(anchor=W)
        self._build_logo(header)

        tabs = ttk.Notebook(self.root)
        tabs.pack(fill=BOTH, expand=True, padx=12, pady=(0, 12))

        self.ficha_tab = Frame(tabs, padx=12, pady=12, bg=APP_BG)
        self.summary_tab = Frame(tabs, padx=12, pady=12, bg=APP_BG)
        self.proposals_tab = Frame(tabs, padx=12, pady=12, bg=APP_BG)

        tabs.add(self.ficha_tab, text="Ficha")
        tabs.add(self.summary_tab, text="Resumo Final")
        tabs.add(self.proposals_tab, text="Propostas")

        self.ficha_canvas = Canvas(self.ficha_tab, bg=APP_BG, highlightthickness=0)
        self.ficha_canvas.pack(side=LEFT, fill=BOTH, expand=True)
        self.ficha_scrollbar = ttk.Scrollbar(self.ficha_tab, orient=VERTICAL, command=self.ficha_canvas.yview)
        self.ficha_scrollbar.pack(side=RIGHT, fill="y")
        self.ficha_canvas.configure(yscrollcommand=self.ficha_scrollbar.set)
        self.ficha_content = Frame(self.ficha_canvas, bg=APP_BG)
        self.ficha_window = self.ficha_canvas.create_window((0, 0), window=self.ficha_content, anchor="nw")
        self.ficha_content.bind("<Configure>", lambda _: self.ficha_canvas.configure(scrollregion=self.ficha_canvas.bbox("all")))
        self.ficha_canvas.bind("<Configure>", self._resize_ficha_content)
        self.ficha_canvas.bind_all("<MouseWheel>", self._on_ficha_mousewheel)

        self._build_ficha()
        self._build_summary()
        self._build_proposals()

    def _on_ficha_mousewheel(self, event):
        if self.ficha_canvas.winfo_exists():
            self.ficha_canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")

    def _resize_ficha_content(self, event):
        self.ficha_canvas.itemconfigure(self.ficha_window, width=max(event.width - 4, 200))

    def _build_logo(self, parent):
        logo_path = Path(LOGO_FILE)
        if not logo_path.exists():
            logo_path = Path(__file__).with_name(LOGO_FILE)
        if logo_path.exists() and Image and ImageTk:
            try:
                image = Image.open(logo_path)
                image.thumbnail((420, 90))
                self.logo_image = ImageTk.PhotoImage(image)
                Label(parent, image=self.logo_image, bg=HEADER_BG).pack(side=RIGHT, padx=(12, 0))
                return
            except Exception:
                pass
        Label(parent, text="franco\ncontabilidade", font=("Segoe UI", 18, "bold"), bg=HEADER_BG, fg="#003B5C", justify=RIGHT).pack(side=RIGHT)

    def _make_var(self, name: str, default: str) -> StringVar:
        var = StringVar(value=default)
        var.trace_add("write", lambda *_: self._on_form_change(name))
        self.form_vars[name] = var
        return var

    def _field(self, parent, row, col, label, name, default="", values=None, width=18):
        bg_color = parent.cget("bg")
        Label(parent, text=label, bg=bg_color, fg="#003B5C", font=("Segoe UI", 10, "bold")).grid(row=row, column=col * 2, sticky=W, padx=(0, 6), pady=4)
        var = self._make_var(name, default)
        if values:
            widget = ttk.Combobox(parent, textvariable=var, values=values, state="readonly", width=width)
        else:
            widget = Entry(parent, textvariable=var, width=width, bg="white")
        self.form_widgets[name] = widget
        widget.grid(row=row, column=col * 2 + 1, sticky=W, padx=(0, 18), pady=4)
        if name == "annual_gross_revenue":
            widget.bind("<FocusOut>", lambda _event: self._format_revenue_field())
        if name == "cnpj":
            widget.bind("<FocusOut>", lambda _event: self._format_cnpj_field())
        return widget

    def _set_view_mode(self, enabled: bool):
        self.view_only_mode = enabled
        if hasattr(self, "view_mode_label"):
            self.view_mode_label.config(text="Visualização" if enabled else "")
        if hasattr(self, "exit_view_button"):
            if enabled:
                if not self.exit_view_button.winfo_ismapped():
                    self.exit_view_button.pack(side=LEFT, padx=(12, 0))
            else:
                if self.exit_view_button.winfo_ismapped():
                    self.exit_view_button.pack_forget()
        for widget in self.form_widgets.values():
            try:
                if isinstance(widget, ttk.Combobox):
                    widget.config(state="disabled" if enabled else "readonly")
                else:
                    widget.config(state="readonly" if enabled else "normal")
            except Exception:
                pass
        if hasattr(self, "status_buttons"):
            for button in self.status_buttons.values():
                button.config(state="disabled" if enabled else "normal")
        if hasattr(self, "clear_button"):
            self.clear_button.config(state="disabled" if enabled else "normal")
        if hasattr(self, "group_checkbox"):
            self.group_checkbox.config(state="disabled" if enabled else "normal")

    def exit_view_mode(self):
        if not self.view_only_mode:
            return
        restore = self.view_mode_restore_state
        self._set_view_mode(False)
        if restore:
            self.ficha_store = copy.deepcopy(restore["ficha_store"])
            self.current_ficha.set(restore["current_ficha"])
            self.view_mode_restore_state = None
            self._load_ficha(self._current_name())
            self.recalculate()
            return
        self._load_ficha(self._current_name())
        self.recalculate()

    def _format_revenue_field(self):
        if "annual_gross_revenue" not in self.form_vars:
            return
        value = self.form_vars["annual_gross_revenue"].get().strip()
        if not value:
            return
        self.form_vars["annual_gross_revenue"].set(money(to_float(value)))

    def _format_cnpj_field(self):
        if "cnpj" not in self.form_vars:
            return
        value = re.sub(r"\D", "", self.form_vars["cnpj"].get())
        if len(value) != 14:
            return
        formatted = f"{value[:2]}.{value[2:5]}.{value[5:8]}/{value[8:12]}-{value[12:]}"
        self.form_vars["cnpj"].set(formatted)

    def _section_frame(self, parent, title: str, subtitle: str) -> Frame:
        section = Frame(parent, bg="white", bd=1, relief="solid", padx=12, pady=10)
        section.pack(fill=X, pady=(0, 10))
        Label(section, text=title, bg="white", fg="#003B5C", font=("Segoe UI", 12, "bold")).pack(anchor=W)
        Label(section, text=subtitle, bg="white", fg="#5A7184", font=("Segoe UI", 9)).pack(anchor=W, pady=(2, 10))
        body = Frame(section, bg="white")
        body.pack(fill=X)
        return body

    def _build_ficha(self):
        parent = self.ficha_content
        selector = Frame(parent, bg=APP_BG)
        selector.pack(fill=X)
        Label(selector, text="Ficha ativa", bg=APP_BG, fg="#003B5C", font=("Segoe UI", 10, "bold")).pack(side=LEFT, padx=(0, 8))
