    def _current_name(self) -> str:
        return self.current_ficha.get()

    def _current_store(self) -> dict:
        return self.ficha_store[self._current_name()]

    def base_ficha_name(self, ficha_name: str) -> str:
        match = re.match(r"^(Ficha\s+\d+)", ficha_name)
        return match.group(1) if match else ficha_name

    def _switch_ficha(self):
        self._set_view_mode(False)
        self._load_ficha(self._current_name())
        self.recalculate()

    def _load_ficha(self, ficha_name: str):
        self.is_loading_ficha = True
        store = self.ficha_store[ficha_name]
        for key, var in self.form_vars.items():
            var.set(store["values"].get(key, DEFAULT_FICHA_TEMPLATE.get(key, "")))
        self.group_var.set(1 if str(store["values"].get("is_group", "0")) == "1" else 0)
        self.is_loading_ficha = False
        self._update_status_buttons()

    def _on_group_toggle(self):
        if self.is_loading_ficha:
            return
        value = "1" if self.group_var.get() else "0"
        for store in self.ficha_store.values():
            store["values"]["is_group"] = value
        self.refresh_summary()

    def _apply_single_ficha_payload(self, ficha_name: str, values: dict, status: str = "", record_name: str | None = None, unit_overrides: dict | None = None):
        self.ficha_store[ficha_name]["values"] = {**DEFAULT_VALUES, **values}
        self.ficha_store[ficha_name]["status"] = status
        self.ficha_store[ficha_name]["record_ficha_name"] = record_name or ficha_name
        self.ficha_store[ficha_name]["unit_overrides"] = dict(unit_overrides or {})
        rows, totals = self.model.calculate(self.ficha_store[ficha_name]["values"], self.ficha_store[ficha_name]["unit_overrides"])
        self.ficha_store[ficha_name]["rows"] = rows
        self.ficha_store[ficha_name]["totals"] = totals

    def _reset_ficha_store(self, ficha_names: list[str] | None = None):
        target_names = ficha_names or FICHA_NAMES
        for ficha_name in target_names:
            self.ficha_store[ficha_name] = {
                "values": dict(DEFAULT_FICHA_TEMPLATE),
                "rows": [],
                "totals": {"monthly_full": 0.0, "monthly_contract": 0.0, "annual_full": 0.0, "annual_contract": 0.0},
                "status": "",
                "record_ficha_name": ficha_name,
                "unit_overrides": {},
            }

    def _apply_proposal_to_ficha(self, ficha_name: str, payload: dict, status: str | None = None, record_name: str | None = None):
        if payload.get("_group_mode") and payload.get("_group_data"):
            self._reset_ficha_store()
            shared_record_name = record_name or payload.get("_record_ficha_name", ficha_name)
            shared_status = status or payload.get("_status", "")
            for member_name, member_data in payload.get("_group_data", {}).items():
                member_values = dict(member_data.get("values", {}))
                member_values["is_group"] = "1"
                self._apply_single_ficha_payload(
                    member_name,
                    member_values,
                    shared_status,
                    shared_record_name,
                    member_data.get("unit_overrides", {}),
                )
            return
        values = {key: value for key, value in payload.items() if not key.startswith("_")}
        self._apply_single_ficha_payload(
            ficha_name,
            values,
            status or payload.get("_status", ""),
            record_name or payload.get("_record_ficha_name", ficha_name),
            payload.get("_unit_overrides", {}),
        )

    def _on_form_change(self, name: str):
        if self.is_loading_ficha:
            return
        self._current_store()["values"][name] = self.form_vars[name].get()
        self.recalculate()

    def current_values(self) -> dict:
        return {key: var.get() for key, var in self.form_vars.items()}

    def current_rows(self) -> list[PriceRow]:
        return self._current_store()["rows"]

    def current_extras_total(self) -> float:
        return 0.0

    def effective_monthly_contract_for_store(self, store: dict) -> float:
        discounted_value = to_float(store["values"].get("granted_discount_value", ""))
        return discounted_value if discounted_value > 0 else store["totals"].get("monthly_contract", 0.0)

    def proposal_scope_fichas(self) -> list[str]:
        if str(self._current_store()["values"].get("is_group", "0")) != "1":
            return [self._current_name()]
        members = [name for name in FICHA_NAMES if self.ficha_has_data(name)]
        return members or [self._current_name()]

    def proposal_totals_for_scope(self, ficha_names: list[str]) -> dict:
        return {
            "monthly_full": sum(self.ficha_store[name]["totals"].get("monthly_full", 0.0) for name in ficha_names),
            "monthly_contract": sum(self.effective_monthly_contract_for_store(self.ficha_store[name]) for name in ficha_names),
            "annual_full": sum(self.ficha_store[name]["totals"].get("annual_full", 0.0) for name in ficha_names),
            "annual_contract": sum(self.effective_monthly_contract_for_store(self.ficha_store[name]) * 13 for name in ficha_names),
        }

    def build_proposal_payload(self, status: str, record_name: str, base_ficha_name: str) -> dict:
        word_template_file = find_word_template()
        store = self._current_store()
        payload = {
            **store["values"],
            "_status": status,
            "_record_ficha_name": record_name,
            "_base_ficha_name": base_ficha_name,
            "_word_template_file": str(word_template_file),
            "_word_template_name": word_template_file.name,
            "_unit_overrides": store.get("unit_overrides", {}),
        }
        scope = self.proposal_scope_fichas()
        if len(scope) > 1 or str(store["values"].get("is_group", "0")) == "1":
            group_data = {}
            for ficha_name in scope:
                member_store = self.ficha_store[ficha_name]
                member_values = dict(member_store["values"])
                member_values["is_group"] = "1"
                group_data[ficha_name] = {
                    "values": member_values,
                    "unit_overrides": dict(member_store.get("unit_overrides", {})),
                }
            payload["is_group"] = "1"
            payload["_group_mode"] = True
            payload["_group_members"] = scope
            payload["_group_data"] = group_data
        return payload

    def clear_current_ficha(self):
        ficha_name = self._current_name()
        self._set_view_mode(False)
        group_value = self.ficha_store[ficha_name]["values"].get("is_group", "0")
        self._reset_ficha_store([ficha_name])
        self.ficha_store[ficha_name]["values"]["is_group"] = group_value
        self._load_ficha(ficha_name)
        self.recalculate()

    def recalculate(self):
        for store in self.ficha_store.values():
            rows, totals = self.model.calculate(store["values"], store.get("unit_overrides"))
            store["rows"] = rows
            store["totals"] = totals
        self.refresh_tree()
        self.refresh_summary()

    def column_totals(self, rows: list[PriceRow]) -> dict:
        return {
            "qty": sum(row.qty for row in rows),
            "unit": sum(row.unit for row in rows),
            "subtotal": sum(row.subtotal for row in rows),
            "discount": sum(row.discount for row in rows),
            "share": sum(row.share for row in rows),
            "contract": sum(row.contract for row in rows),
            "total": sum(row.total for row in rows),
        }

    def unit_options_for_row(self, seq: str) -> list[float]:
        values = self._current_store()["values"]
        segment = values["segment"]
        table = values["table"]
        tax_code = self.model.params.get(values["tax"], "")
        if seq == "1.2":
            return self.model.unit_values(tax_code, segment, table)
        if seq == "1.4":
            return [round(value * 0.10, 10) for value in self.model.unit_values(tax_code, segment, table)]
        if seq in {"2.1", "3.1", "3.2", "4.1", "4.2", "4.3", "4.4", "4.6", "5.1"}:
            return self.model.unit_values(seq, segment, table)
        return []

    def base_reference_for_row(self, seq: str) -> tuple[str, str, list[float]] | None:
        values = self._current_store()["values"]
        segment = values["segment"]
        table = values["table"]
        tax_code = self.model.params.get(values["tax"], "")

        if seq == "1.2":
            return tax_code, f"Tributação Federal | {segment} | {table}", self.model.base_row_values(tax_code, segment, table)
        if seq == "1.4":
            base_values = self.model.base_row_values(tax_code, segment, table)
            return tax_code, f"Empresa com Filiais (10% da Tributação Federal) | {segment} | {table}", [value * 0.10 for value in base_values]
        if seq in {"2.1", "3.1", "3.2", "4.1", "4.2", "4.3", "4.4", "4.6", "5.1"}:
            return seq, f"{segment} | {table}", self.model.base_row_values(seq, segment, table)
        return None

    def _close_unit_editor(self):
        if self.unit_editor is not None:
            self.unit_editor.destroy()
            self.unit_editor = None
            self.unit_editor_item = None

    def _save_unit_edit(self, _event=None):
        if self.unit_editor is None or self.unit_editor_item is None:
            return
        raw_value = self.unit_editor.get().strip()
        value = to_float(raw_value)
        if value > 0:
            self._current_store().setdefault("unit_overrides", {})[self.unit_editor_item] = value
        self._close_unit_editor()
        self.recalculate()

    def _begin_unit_edit(self, event):
        if self.view_only_mode:
            return
        row_id = self.price_tree.identify_row(event.y)
        column_id = self.price_tree.identify_column(event.x)
        if not row_id or row_id == "__total__" or column_id != "#5":
            return
        options = self.unit_options_for_row(row_id)
        if not options:
            return
        self._close_unit_editor()
        x, y, width, height = self.price_tree.bbox(row_id, column_id)
        display_values = [money(value) for value in options]
        self.unit_editor_item = row_id
        self.unit_editor = ttk.Combobox(self.price_tree, values=display_values, state="readonly")
        self.unit_editor.place(x=x, y=y, width=width, height=height)
        current_value = self.price_tree.item(row_id, "values")[4]
        self.unit_editor.set(current_value)
        self.unit_editor.bind("<<ComboboxSelected>>", self._save_unit_edit)
        self.unit_editor.bind("<FocusOut>", lambda _event: self._close_unit_editor())
        self.unit_editor.focus_set()

    def show_base_reference(self):
        selection = self.price_tree.selection()
        if not selection:
            messagebox.showwarning("Base", "Selecione uma linha da grade para conferir a base.")
            return
        row_id = selection[0]
        if row_id == "__total__":
            messagebox.showwarning("Base", "Selecione uma linha de cálculo, não o total.")
            return

        row = next((item for item in self.current_rows() if item.seq == row_id), None)
        reference = self.base_reference_for_row(row_id)
        if row is None or reference is None:
            messagebox.showwarning("Base", "Não encontrei a referência da base para esta linha.")
            return

        code, title, values = reference
        window = Toplevel(self.root)
        window.title("Conferência da Base")
        window.geometry("720x360")
        window.configure(bg=APP_BG)
        window.transient(self.root)

        Label(window, text=f"{row.seq} - {row.description}", bg=APP_BG, fg="#003B5C", font=("Segoe UI", 12, "bold")).pack(anchor=W, padx=12, pady=(12, 4))
        Label(window, text=f"Código base: {code} | {title}", bg=APP_BG, fg="#4C647A", font=("Segoe UI", 10)).pack(anchor=W, padx=12)

        text = Text(window, wrap="word", bg="white", fg="#1F1F1F", font=("Segoe UI", 10))
        text.pack(fill=BOTH, expand=True, padx=12, pady=(10, 12))
        text.insert(END, "Valores encontrados na base:\n\n")
        for index, value in enumerate(values, 1):
            text.insert(END, f"Nível {index}: {money(value)}\n")
        text.insert(END, f"\nValor atual na ficha: {money(row.unit)}")
        text.config(state="disabled")

